import os

def generate_requirements(file='requirements.txt', upgrade=True):
    if not os.path.exists(file):
        print('File does not exist')
        return
    
    command = 'pip install -r {}'.format(file)
    
    if upgrade:
        command += ' --upgrade'
        
    os.system(command)

generate_requirements()